member.example:
Bind the line type of a TMP_InputField using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldLineTypeBinder _lineType;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TMP_InputField.LineType _lineType;
    }


Bind the line type of a TMP_InputField by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_InputField _inputField;
        
        private InputFieldLineTypeBinder LineType =>
            new(_inputField);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TMP_InputField.LineType _lineType;
    }

Switch the line type of a TMP_InputField between two values using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldLineTypeSwitcherBinder _isMultiLine;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isMultiLine;
    }


Switch the line type of a TMP_InputField between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_InputField _inputField;
        
        private InputFieldLineTypeSwitcherBinder IsMultiLine => new(
            _inputField,
            TMP_InputField.LineType.MultiLineNewline,
            TMP_InputField.LineType.SingleLine);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isMultiLine;
    }
